<?php session_start(); include '../includes/db.php'; if(!isset($_SESSION['user_id']) || $_SESSION['role'] !== 'admin'){ header('Location: ../login.php'); exit(); } $result=$conn->query("SELECT id, full_name, email, phone, role, created_at FROM users ORDER BY created_at DESC"); include '../includes/header.php'; ?>
<section class="page-section"><div class="container"><h1 class="section-title">Customers</h1><div class="order-history-table-wrapper"><table class="order-history-table"><thead><tr><th>ID</th><th>Name</th><th>Email</th><th>Phone</th><th>Role</th><th>Joined</th></tr></thead><tbody><?php if($result && $result->num_rows>0): while($row=$result->fetch_assoc()): ?><tr><td><?= $row['id'] ?></td><td><?= htmlspecialchars($row['full_name']) ?></td><td><?= htmlspecialchars($row['email']) ?></td><td><?= htmlspecialchars($row['phone']) ?></td><td><?= htmlspecialchars($row['role']) ?></td><td><?= htmlspecialchars($row['created_at']) ?></td></tr><?php endwhile; else: ?><tr><td colspan="6">No users found.</td></tr><?php endif; ?></tbody></table></div></div></section>
